import crypto from 'crypto';

const SECRET = process.env.OTP_SECRET || 'default-secret-change-me';

export function generateOTP(): string {
  // Generate a random 4-digit number
  return crypto.randomInt(1000, 10000).toString();
}

export function hashOTP(email: string, otp: string, expiresAt: number): string {
  const data = `${email}.${otp}.${expiresAt}`;
  return crypto.createHmac('sha256', SECRET).update(data).digest('hex');
}

export function verifyOTP(email: string, otp: string, hash: string, expiresAt: number): boolean {
  if (Date.now() > expiresAt) {
    return false;
  }
  const computedHash = hashOTP(email, otp, expiresAt);
  return computedHash === hash;
}
